// List the RSS/Atom feeds you want digested. One item per feed.
// Replace these example feeds with your own.
const feeds = [
  'https://example.com/feed.xml',
  'https://example.org/rss',
  'https://news.example.net/atom'
];
return feeds.map((url) => ({ json: { url } }));

// Keep only items from the last 24h and compile a compact list for the model.
const SINCE_MS = 24 * 60 * 60 * 1000;
const now = Date.now();
const items = $input.all().map((it) => it.json);
const recent = items.filter((a) => {
  const d = new Date(a.isoDate || a.pubDate || a.date || 0).getTime();
  return d && now - d <= SINCE_MS;
});
const use = (recent.length ? recent : items).slice(0, 40);
if (!use.length) {
  return [{ json: { compiled: 'NO_ITEMS' } }];
}
const lines = use.map((a, i) => {
  const title = (a.title || '(no title)').replace(/\s+/g, ' ').trim();
  const link = a.link || a.guid || '';
  const snippet = (a.contentSnippet || a.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').slice(0, 160);
  return `${i + 1}. ${title}\n   ${snippet}\n   ${link}`;
});
return [{ json: { count: use.length, compiled: lines.join('\n\n') } }];

